       87: }
       88: 
       89: /// Resolve positional `..` args with named flag overrides.
       90: ///
       91: /// - `pos_rev`: first positional arg (may contain `..`)
       92: /// - `pos_count`: second positional arg
       93: /// - `flag_rev`: `-r` flag value (if different from default)
       94: /// - `flag_limit`: `-l` flag value
       95: /// - `default_rev`: the default revision (e.g. "@")
       96: pub fn resolve_dot_args(
       97:     pos_rev: Option<&str>,
       98:     pos_count: Option<usize>,
       99:     flag_rev: &str,
      100:     flag_limit: Option<usize>,
      101:     default_rev: &str,
      102: ) -> ResolvedArgs {
      103:     // If named flags were explicitly set, they take full precedence
      104:     let flag_rev_set = flag_rev != default_rev;
      105:     let flag_limit_set = flag_limit.is_some();
      106: 
      107:     if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
